const Q_PHYSICS_2021_MODEL_II=[{"id": "objective>Physics>2021 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">20g of a liquid evaporates at its boiling point , when a coil of resistance 4Ω in which a current of 0.2A flows for 1 min in inserted. Determine the specific latent heat of vaporization of the liquid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2400Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">620Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">480Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Mass,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.02kg</td></tr></table></div> <br/> Resistance, R = 4Ω <br/> Current, I = 0.2A <br/> time, t = 1 min = 60s <br/> Specific latent heat of vaporization, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> =? <br/> ml<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Rt <br/> 0.02l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = 0.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> x 4 x 60 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> x 4 x 60<hr size=\"1\" />0.02</td></tr></table></div> <br/> l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = 480Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2021 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is correct for evaporation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It occurs at a fixed temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is affected by wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It occurs in the entire liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It doesn't lead to cooling</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The table below shows the difference between evaporation and boiling. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Evaporation</td><td style=\"border:1px solid black;text-align:center;\">Boiling <br/> [i. It occurs below the boiling point</td><td style=\"border:1px solid black;text-align:center;\">i. It occurs at a fixed temperature.</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">ii. It is a surface phenomenum</td><td style=\"border:1px solid black;text-align:center;\">ii. It occurs in the entire liquid.</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">iii. It is affected by wind</td><td style=\"border:1px solid black;text-align:center;\">iii. It is not affected by wind</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">iv. It leads to cooling</td><td style=\"border:1px solid black;text-align:center;\">iv. It doesn't lead to cooling</td></tr></table></div></div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2021 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the stress on a wire is 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> and the wire is stretched from its original length of 10.00cm to 10.05cm, the Young's modulus of the wire is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stress = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Original length, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10.00cm <br/> New length, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 10.05cm <br/> extension, e = 10.05 - 10.00 = 0.05cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">strain</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">extension, e<hr size=\"1\" />original length, l</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05<hr size=\"1\" />10.00</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.005</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Young's</td><td style=\"text-align:center;\">modulus</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Tensile Stress<hr size=\"1\" />Tensile strain</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span><hr size=\"1\" />5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7-(-3)</span></td></tr></table></div> = 0.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span> <br/> 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2021 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is correct about the electroplating of iron spoon with silver?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Concentration level of the electrolyte reduces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silver nitrate is used as the electrolyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silver rod is made the cathode </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The spoon is made the anode </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an active anode is used in an electrolysis i.e a metal whose salt is used as the electrolyte, then the anode dissolves in the solution and it is deposited at the cathode. In a case where iron spoon is to be electroplated with silver, the silver is made the anode while the iron spoon is made the cathode. <br/> The electrolyte is silver nitrate (AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>), and the concentration of the electrolyte remains unchanged since it is the dissolve silver that is deposited on the iron spoon.</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2021 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The displacement of a lorry is given as  <br/> x = t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> - 2t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 4t + 7 such that X is in metres and t is in seconds. At what time will the lorry be momentarily at rest?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lorry will be momentarily at rest when dx/dt = 0  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">dx<hr size=\"1\" />dt</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">velocity</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">dx<hr size=\"1\" />dt</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">4t</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0</td></tr></table></div> <br/> 3t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 4t - 4 = 0 <br/> 3t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 6t + 2t - 4 = 0 <br/> 3t(t - 2) + 2(t - 2) = 0 <br/> (t - 2)(3t + 2) = 0 <br/> t - 2 = 0 or 3t + 2 = 0 <br/> t = 2 or t = -2/3 (time cannot be negative) <br/> ∴ The time is 2s.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2021 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the pressure at the bottom of an ocean 8m if the atmospheric pressure due to water is 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. [Density of water = 1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.20 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.28 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total pressure at the bottom is the sum of the atmospheric pressure and the pressure of water. <br/> P = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> <br/> Atmospheric pressure, Pa = 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Pressure due to the water, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = ρgh <br/> ⇒ 1000 x 10 x 8 <br/> ⇒ 8000 <br/> ⇒ 0.08 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> P = 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> + 0.08 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/> P = 1.28 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2021 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these pair of colours are complementary?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Blue and yellow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green and Red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blue and green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red and Blue </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In additive colour mixing, complementary colours are pair of colours (primary and secondary) which when mixed in their right proportion give white colour. <br/> Blue + Yellow = White <br/> Red + Cyan = White <br/> Green + Magenta = White</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2021 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the circuit, the potential across each capacitor is 100V. What is the total energy stored in the two capacitors. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 2μF and 3μF capacitors are in parallel <br/> C = 2μF + 3μF <br/> C = 5μF <br/> V = 100V <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Energy,</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">CV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></td></tr></table></div> <br/> E = 2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>", "topic": "CAPACITORS : ENERGY STORED IN A CAPACITOR"}, {"id": "objective>Physics>2021 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will produce the loudest sound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A thick short string</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A thick long string </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A thin short string </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A thin long string </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The thickness (diameter) of the string contributes to its stiffness, and thicker strings can produce louder sounds. <br/> The length of the string affects the wavelength, and longer strings can produce lower-frequency sounds, which may be perceived as louder.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2021 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shallowness of a swimming pool is due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Refraction is the bending effect of wave after crossing the boundary between two media of different densities. A swimming pool appears shallow because light has crossed from air to water which are two media of different densities.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2021 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows a see-saw with three boys of weight 32.5Kgf, 20kgf and 15kg sitting on it. If the see-saw is exactly horizontal and of negligible weight, the value of x is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2021 Model II/phy14.png\" style=\"position:relative;max-width:100%;\"/> <br/> Using the principle of moment <br/> Sum of clockwise moment = Sum of anticlockwise moment <br/> 20 × x + 15(x + 2) = 32.5 × 2 <br/> 20x + 15x + 30 = 65 <br/> 35x = 65 - 30 <br/> 35x = 35 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">35<hr size=\"1\" />35</td></tr></table></div> <br/> x = 1.0m </div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2021 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of moisting the fingers before counting money can be explained using </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">surface tension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cohesive force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesive force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capillarity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adhesive force is the force of attraction between molecules of different substances or kinds. The force of attraction between the molecules of water and the molecules of the fingers make the counting of money easier.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2021 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle vibrated with simple harmonic motion. If its acceleration in ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> is 25 times its displacement in metres, find the period of the motion in terms of π</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.08πs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.12πs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20πs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40πs</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">a = 25x  <br/> where a = acceleration <br/> x = displacement <br/> Recall, <br/> a = ω<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>x <br/> where ω = angular velocity <br/> ω<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>x = 25x <br/> ω<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 25 <br/> ω = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">25&nbsp;</span> <br/> ω = 5rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall, <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ω</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />T</td></tr></table></div> <br/> Where T = Period  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />T</td></tr></table></div> <br/> 5T = 2π <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />5</td></tr></table></div> <br/> T = 0.40πs</div>", "topic": "SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2021 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 20N starts a body from rest and accelerates it uniformly at 2m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> for 4s. Determine the workdone by the force. <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">220J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">320J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Force, F = 20N <br/> acceleration, a = 2m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> time, t = 4s <br/> Initial velocity, U = 0m/s <br/> Recall, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">S</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ut</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">S</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0(4)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> S = 0 + 16 <br/> S = 16m <br/> Recall, <br/> Workdone = Force x Distance <br/> W = 20 x 16 <br/> W = 320N</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2021 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the dimension of resistance is written as  <br/> M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">w</span>. What are the values of w, z, y and x respectively. <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1, 2, -3, -2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1, 2, -2, -2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2, -3, 2, 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3, 1, -1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From Ohm's law <br/> V = IR <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />I</td></tr></table></div> <br/> Where V = Potential difference <br/> I = current <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall,</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<hr size=\"1\" />Q</td></tr></table></div> <br/> Where W = workdone <br/> Q = Quantity of charge <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<hr size=\"1\" />Q</td><td style=\"text-align:center;\">&#215;</td><td style=\"text-align:center;\">1<hr size=\"1\" />I</td></tr></table></div> <br/> But, W = Fd <br/> Q = It <br/> where F = Force, d = distance, t = time <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Fd<hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>t</td></tr></table></div> <br/> But F = ma <br/> where m = mass, a = acceleration <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mad<hr size=\"1\" />I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>t</td></tr></table></div> <br/> units: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Kg.ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.m<hr size=\"1\" />A<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>s</td></tr></table></div> <br/> Kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>A<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> Dimension: <br/> ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> ∴ x = 1, y = 2, z = -3, w = -2. <br/>  <br/> ∴ the values of w, z, y and x are -2, -3, 2, 1.</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY~~MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2021 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following objects is in a state of neutral equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a stable equilibrium, a slight displacement increases the centre of gravity and the body returns to its original position. <br/> In an unstable equilibrium, a slight displacement decreases the centre of gravity of the body and it doesn't return to its original position. <br/> In a neutral equilibrium, a slight displacement doesn't affect the centre of gravity of the body.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2021 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following bodies exhibits translational and rotational motions simultaneously?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Book sliding down an inclined table </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A stone released from the top of a cliff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A butterfly hovering over a flower </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cylinder rolling down an inclined plane.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fact that the cylinder rolls down the plane makes it rotational. Its movement down the plane is translational. Hence, it performs both rotational and translational motion down the plane.</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2021 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these sources of light is non-luminous?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stars </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fireflies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">moon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sun</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A non-luminous source of light is that source which doesn't produce its own light but reflects the light from other source.</div>", "topic": "LIGHT ENERGY : SOURCE OF LIGHT"}, {"id": "objective>Physics>2021 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what angle must a bullet be fired it its range must be equal to its maximum height?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">76°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Range,</td><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin2θ<hr size=\"1\" />g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Maximum</td><td style=\"text-align:center;\">Height,</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2g</td></tr></table></div> <br/> R = Hm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin2θ<hr size=\"1\" />g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2g</td></tr></table></div> <br/> 2sin2θ = sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ <br/> From trigonometry <br/> sin2θ = 2sinθcosθ <br/> 2[2sinθcosθ] = sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ <br/> 4sinθcosθ = sin sinθ <br/> 4cosθ = sin θ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">sinθ<hr size=\"1\" />cosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">But</td><td style=\"text-align:center;\">sinθ<hr size=\"1\" />cosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">tanθ</td></tr></table></div> <br/> tanθ = 4 <br/> θ = tan<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>4 <br/> θ = 75.96 <br/> θ = 76°</div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2021 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. High pressure <br/> II. High potential difference <br/> III. Low pressure <br/> IV. Low potential difference <br/> Which of the above conditions are necessary for gas to conduct electricity.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gases are generally insulators but when subjected to low pressure and high potential difference, they become conductor of electricity.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2021 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Using the diagram above as a guide, determine the pressure of the gas. [Atmospheric pressure = 75cmHg] </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">85.1cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90.4cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">87.6cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">77.5cmHg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2021 Model II/phy17.png\" style=\"position:relative;max-width:100%;\"/> <br/> The pressure at X and Y are the same since both arms contain mercury. Therefore the pressure of the gas at Y is the same as the sum of pressure due to column WX and the atmospheric pressure. <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">gas</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">atm</span> + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">wx</span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">gas</span> = 75cmHg + (12.6 - 2.5)cmHg <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">gas</span> = 75cmHg + 10.1 cmHg <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">gas</span> = 85.1cmHg </div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2021 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the reading on the vernier calliper below? <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.74cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.74cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.36cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.46cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mainscale reading is the last reading before the vernier scale start i.e 2.70cm <br/> The vernier scale reading is the reading which coincides with a reading on the main scale i.e 0.04cm (It is 100th of the reading on the main scale). <br/> Vernier calliper reading  <br/> = 2.70cm <br/> &nbsp &nbsp 0.04cm <br/> ⇒ 2.74cm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2021 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these units is derived?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kelvin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coulomb</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ampere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mole </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A derived quantity has a derived unit while a fundamental quantity has a fundamental unit. Kelvin, Ampere and mole are fundamental units for temperature, electric current and amount of substance respectively. Coulomb is a derived unit for quantity of charge.</div>", "topic": "MEASUREMENTS AND UNITS : DERIVED PHYSICAL QUANTITIES AND THEIR UNITS"}, {"id": "objective>Physics>2021 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A load of 80N is suspended using a string. <br/> A rope is used to pull the load horizontally until the string makes angle 60° to the vertical. Determine the tension in the string.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">92N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">160N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"2021 Model II/phy19a.png\" style=\"position:relative;max-width:100%;\"/> <img src=\"2021 Model II/phy19b.png\" style=\"position:relative;max-width:100%;\"/> <br/> Since the body is in equilibrium, then vertical upward force is equal to vertical downward force. <br/> <img src=\"2021 Model II/phy19c.png\" style=\"position:relative;max-width:100%;\"/> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> is the vertical component of T <br/> From trigonometry, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">cos60°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span><hr size=\"1\" />T</td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = Tcos60° <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 0.5T <br/>  <br/> <img src=\"2021 Model II/phy19d.png\" style=\"position:relative;max-width:100%;\"/> <br/>  T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 80 <br/> 0.5T = 80 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />0.5</td></tr></table></div> <br/> T = 160N   </div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2021 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man changes its position from R(2, -3) to S(7, P). If the distance covered is 13km, what is the value of p.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R(2, -3) <br/> ⇒ x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2, y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 3 <br/> S(7, P) <br/> ⇒ x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 7, y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = P <br/> Distance, RS = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">(x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + (y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - y<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> <br/> 13= &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">(7 - 2)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + (P - (-3))<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> <br/> 13 = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + (P + 3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> <br/> 13<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  = 25 + (P + 3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 169 - 25 = (P + 3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 144 = (P + 3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">144&nbsp;</span> = P + 3 <br/> P + 3 = ±12 <br/> P = -3 ± 12 <br/> P = -3 + 12 or P = -3 -12 <br/> P = 9 or -15</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2021 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Water wave at the surface <br/> II. Water wave at a particular depth <br/> III. Wave generated from a vibrating string <br/> IV. Radio waves <br/> Which of the above are transverse</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transverse waves are waves in which their flow of energy is perpendicular to their particle flow. Examples are water wave at the surface, all electromagnetic waves, wave generated from a vibrating string.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2021 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A relative density bottle of volume 40cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is completely filled with a liquid at 25°C. It is then heated to 90°C such that 0.82cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of the liquid is expelled. <br/> Calculate the apparent cubic expansivity of the liquid. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.15 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.22 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.33 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.37 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Apparent</td><td style=\"text-align:center;\">cubic</td><td style=\"text-align:center;\">expansivity,</td><td style=\"text-align:center;\">γ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Volume expelled<hr size=\"1\" />volume left × temperature rise</td></tr></table></div> <br/> Volume expelled = 0.82cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Volume left = 40 - 0.82 = 39.18cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Temperature rise = 90°C - 25°C = 65°C <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">γ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.82<hr size=\"1\" />39.18×65</td></tr></table></div> <br/> γ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> = 3.22 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2021 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wire has a resistance of 24 Ω, when the diameter is doubled and the length is also doubled. The new resistance becomes.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48 Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">96 Ω</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance, R, resistivity, ρ, length, l and cross-sectional area of a wire are related by the formula. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">RA<hr size=\"1\" />l</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> Area, A = πr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>; but r = D/2 where D = diameter <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">πD<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 24Ω, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> ; D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">24 x πD<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/4<hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> 24 x D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> Also, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>xπ(2d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> /4<hr size=\"1\" />2l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> x 4D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">24</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> x 4D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24 × 2<hr size=\"1\" />4</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 12Ω</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2021 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is a contact force?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Frictional force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electric force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gravitational force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic force </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A contact force is a force which has a direct application on an object. Frictional force acts between the surface of separation of two bodies in contact and tends to prevent their motion. Hence, friction is a contact force.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2021 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion occurs in  <br/> I. gases <br/> II. liquids <br/> III. solids <br/> Which of the statements above is/are correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion is the tendency of molecules to migrate and fill an empty space. This takes place in solid, liquid and gas, fastest in gas and slowest in solid.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2021 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following electromagnetic  wave is more energetic compared to light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Radio waves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Microwaves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infrared rays </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ultraviolet rays </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The order of increasing energy of electromagnetic waves is radiowaves, microwave, infrared, visible light, ultraviolet rays, x-rays, gamma rays. It can be seen from the options that only ultraviolet ray that is more energetic than light.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>2021 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three concurrent forces act on a body at equilbrium as shown in the diagram below  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The magnitudes of F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> respectively are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">N</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2021 Model II/phy21.png\" style=\"position:relative;max-width:100%;\"/> <br/> 60° + 150° + θ = 360 <br/> 210 + θ = 360 <br/> θ = 360 - 210 <br/> θ = 150° <br/> Using Lami's theorem, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />sin150</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />sin60</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100sin150<hr size=\"1\" />sin60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100 x 1/2<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>/2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td></tr></table></div> <br/> Rationalize  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td></tr></table></div> <br/> Also, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />sin150</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />sin60</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />3</td><td style=\"text-align:center;\">N</td></tr></table></div> </div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2021 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a semi-conductor is heated strongly, its  <br/> I. conductivity increases <br/> II. conductivity reduces  <br/> III. Resistance increases <br/> IV. Resistance reduces </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For metals, increase in temperature leads to an increase in resistance while conductivity decreases. But for semi-conductors, increase in temperature leads to a decrease in resistance and conductivity increases.</div>", "topic": "INTRODUCTORY ELECTRONICS : METALS, SEMICONDUCTORS AND INSULATORS"}, {"id": "objective>Physics>2021 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most precised of the following set of observations is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.25cm, 3.26cm and 3.29cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.19cm, 5.01cm and 5.02cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.32cm, 6.34cm and 6.34cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.03cm, 0.05cm and 0.07cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Precision is a measure of the closeness of observed values. <br/> [6.32cm, 6.34cm and 6.34cm] has the highest precision its precision is 0.02cm i.e 6.34cm - 6.32cm. <br/> [3.25cm, 3.26cm and 3.29cm] has precision of 0.04 i.e 3.29cm - 3.25cm <br/> [4.19cm, 5.01cm and 5.02cm] has precision of 0.83 i.e 5.02cm - 4.19cm <br/> [0.03cm, 0.05cm and 0.07cm] has precision of 0.04 i.e 0.07cm - 0.03cm</div>", "topic": "MEASUREMENTS AND UNITS : LIMITATIONS OF EXPERIMENTAL MEASUREMENTS"}, {"id": "objective>Physics>2021 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where must an object be positioned in front of a concave mirror to produce a virtual image?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At the focus point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the centre of curvature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between focus and centre of curvature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between the pole and focus </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The only position where an object must be placed on a concave mirror in order to produce a virtual image is between the pole and the focus point. A virtual image is always erect and it is formed behind the mirror. <br/> <img src=\"2021 Model II/phy22.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>2021 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these statements are correct? <br/> I. The volume of acid is measured with pipette during titration. <br/> II. Eureka can is used to determine the volume of irregular solid. <br/> III. The volume occupied by gas molecules is negligible compared to the volume of the container. <br/> IV. Measuring cylinder can be used to determine the volume of any liquid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All the statements are correct except for the first one. The volume of acid is determined using burette and not pipette during titration. Pipette is used to determine volume of base.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2021 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain radioactive element of initial mass 160g has a half life of 20 years. After a period of T years, only 5g of the element is left undecayed. The value of T is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">t<hr size=\"1\" />t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span></span></td></tr></table></div> <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = Original mass <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span> = Mass left after time t <br/> t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = half life. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">160<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">T/20</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">32</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">T/20</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">T/20</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td></tr></table></div> <br/> T = 20 x 5 <br/> T = 100</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2021 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The length of an object was accurately measured by a student as 2.6cm. The device used is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metre rule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vernier caliper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tape rule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">micrometre screw gauge </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Each measuring instrument of length has its own accuracy (the smallest which can be obtained accuracy of the instrument), and that of a metre rule is 0.1cm. Hence, 2.6cm must have been gotten from a metre rule.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2021 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these satisfies the condition for a body to float in a fluid? A body floats when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it displaces its own mass of the liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it displaces its own density of the liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it displaces its own volume of the liquid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its density is greater than that of the liquid </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the principle of floatation, a body floats in a fluid when it displaces its own weight of the fluid. <br/> Hence, weight of body is equal to weight of fluid displaced i.e W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span> = W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> <br/> But Weight, W = mg (mass x acceleration due to gravity) <br/> ∴ M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>g = M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span>g <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span> = M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> <br/> Therefore, a body floats in a fluid when it displaced its own mass of the fluid.</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>2021 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these will give a fundamental quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mass x acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Force<hr size=\"1\" />Magnetic flux density x current</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">potential difference x workdone </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Force<hr size=\"1\" />Impulse</td></tr></table></div></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall, <br/> F = BIL <br/> where F = Force; B = magnetic flux density; I = electric current, l = length <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />BI</td></tr></table></div> <br/> Length is a fundamental quantity</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD~~MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}];
